// ❌ 错误方式
NaN === NaN   // false ← NaN 不等于自己！

// ✅ 正确方式
Number.isNaN(NaN)      // true
Number.isFinite(42)    // true（有限数字）
Number.isInteger(3)    // true（整数）

const a = "双引号";          // 最常用
const b = '单引号';          // 也常用
const c = `反引号`;          // ES6 模板字符串

// 模板字符串的威力：
const name = "Alice";
const age = 25;
const msg = `${name} 今年 ${age} 岁`;  // "Alice 今年 25 岁"

// 多行字符串（只有反引号支持）
const poem = `静夜思
床前明月光
疑是地上霜`;

// JS 中只有 6 个 falsy 值：
false          // 布尔 false
0             // 数字零
-0            // 负零
""            // 空字符串
null          // 空值
undefined     // 未定义
NaN           // 非数字

// 其他所有值都是 truthy！包括：
// "0", [], {}, -1, "false" 都是 truthy

// undefined — JS 自动产生的空
let x;                    // undefined
function f() {}           // 返回 undefined

// null — 程序员手动设定的空
let user = null;          // 主动清空

// typeof 的坑
typeof undefined  // "undefined" ✅
typeof null        // "object"    ❌ BUG！

const a = Symbol("id");
const b = Symbol("id");
console.log(a === b);  // false ← 每次都是唯一值！

// 用作对象属性键
const key = Symbol("secret");
const obj = { [key]: "hidden", name: "visible" };
console.log(obj[key]);    // "hidden"
console.log(obj.name);    // "visible"
// Symbol 键不会出现在 for...in 中

const big = 9007199254740991n;   // 后缀 n
const also = BigInt("9007199254740991");

console.log(typeof big);  // "bigint"

// ⚠️ BigInt 不能和 Number 混合运算
// big + 1               // TypeError！
big + BigInt(1)          // OK，显式转换
Number(big)              // 转回 Number（可能丢失精度）

let a = 1;
let b = a;    // b 拷贝了 a 的值 1
b = 2;        // 修改 b
console.log(a);  // 1 ← a 不受影响！
// a 和 b 是两个独立的盒子，各有各的值

let a = { x: 1 };
let b = a;        // b 指向和 a 同一个对象
b.x = 2;          // 通过 b 修改对象
console.log(a.x);  // 2 ← a 也被影响了！
// a 和 b 指向同一个盒子，改一个另一个也变

// 判断 null
if (x === null) { ... }

// 判断数组
Array.isArray([1,2])  // true
Array.isArray({})     // false

// 判断 NaN
Number.isNaN(NaN)     // true

// 判断整数
Number.isInteger(3)   // true
Number.isInteger(3.1) // false

// 判断对象（排除 null）
if (x !== null && typeof x === 'object') { ... }
